def require_auth(func):
    """Decorator to enforce authentication on handler."""
    @wraps(func)
    def wrapper(event, context):
        request_context = event.get("requestContext", {})
        authorizer = request_context.get("authorizer", {})

        # Check for Cognito or custom authorizer claims
        claims = authorizer.get("claims", authorizer.get("jwt", {}).get("claims", {}))
        principal_id = authorizer.get("principalId")

        if not claims and not principal_id:
            logger.warning(
                "Unauthenticated request attempt",
                extra={
                    "service": SERVICE_NAME,
                    "source_ip": request_context.get("identity", {}).get("sourceIp", "unknown"),
                    "path": event.get("path", event.get("rawPath", "unknown")),
                }
            )
            return build_response(401, {"error": "Unauthorized"})

        # Attach auth context to event for downstream use
        event["_auth_context"] = {
            "claims": claims,
            "principal_id": principal_id or claims.get("sub", "unknown"),
        }
        return func(event, context)
    return wrapper


