# ---------------------------------------------------------------------------
# Secure response builder
# ---------------------------------------------------------------------------
def build_response(status_code: int, body: Any, headers: Optional[Dict] = None) -> Dict:
    """Build a secure API Gateway response with security headers."""
    origin = ""
    # If called from API Gateway, check origin
    if isinstance(body, dict) and "_event" in body:
        del body["_event"]

    default_headers = {
        "Content-Type": "application/json",
        "X-Content-Type-Options": "nosniff",
        "X-Frame-Options": "DENY",
        "X-XSS-Protection": "1; mode=block",
        "Strict-Transport-Security": "max-age=63072000; includeSubDomains; preload",
        "Cache-Control": "no-store, no-cache, must-revalidate",
        "Pragma": "no-cache",
        "Content-Security-Policy": "default-src 'none'",
        "Referrer-Policy": "no-referrer",
    }

    if ALLOWED_ORIGINS and ALLOWED_ORIGINS[0]:
        # Only set CORS for allowed origins
        default_headers["Access-Control-Allow-Origin"] = ALLOWED_ORIGINS[0]
        default_headers["Access-Control-Allow-Methods"] = "GET,POST,PUT,DELETE,OPTIONS"
        default_headers["Access-Control-Allow-Headers"] = "Content-Type,Authorization"
        default_headers["Access-Control-Max-Age"] = "86400"

    if headers:
        default_headers.update(headers)

    # Ensure no sensitive data leaks in error responses
    if status_code >= 500 and isinstance(body, dict):
        body = {"error": "Internal server error", "request_id": ""}

    response_body = json.dumps(body, default=str)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": response_body,
    }


# ---------------------------------------------------------------------------
# AWS Service Clients (lazy-initialized, reused across invocations)
# ---------------------------------------------------------------------------
class AWSClients:
    """Lazy-initialized AWS service clients for connection reuse."""

    _dynamodb_table = None
    _sns_client = None
    _sqs_client = None
    _s3_client = None

    @classmethod
    def get_dynamodb_table(cls):
        if cls._dynamodb_table is None:
            if not DYNAMODB_TABLE:
                raise RuntimeError("DYNAMODB_TABLE environment variable not set")
            dynamodb = boto3.resource("dynamodb", region_name=AWS_REGION)
            cls._dynamodb_table = dynamodb.Table(DYNAMODB_TABLE)
        return cls._dynamodb_table

    @classmethod
    def get_sns_client(cls):
        if cls._sns_client is None:
            cls._sns_client = boto3.client("sns", region_name=AWS_REGION)
        return cls._sns_client

    @classmethod
    def get_sqs_client(cls):
        if cls._sqs_client is None:
            cls._sqs_client = boto3.client("sqs", region_name=AWS_REGION)
        return cls._sqs_client

    @classmethod
    def get_s3_client(cls):
        if cls._s3_client is None:
            cls._s3_client = boto3.client("s3", region_name=AWS_REGION)
        return cls._s3_client


