def dynamo_get_item(item_id: str) -> Optional[Dict]:
    """Securely get an item from DynamoDB with validated input."""
    validated_id = validate_id(item_id, "item_id")
    table = AWSClients.get_dynamodb_table()
    try:
        response = table.get_item(Key={"id": validated_id})
        return response.get("Item")
    except ClientError as e:
        logger.error(
            "DynamoDB GetItem failed",
            extra={"service": SERVICE_NAME, "error": str(e), "item_id": validated_id}
        )
        raise


def dynamo_put_item(item: Dict[str, Any]) -> Dict:
    """Securely put an item into DynamoDB with validated input."""
    if "id" not in item:
        raise InputValidationError("Item must contain an 'id' field")

    validate_id(item["id"], "item.id")

    # Validate all string fields to prevent injection
    sanitized_item = {}
    for key, value in item.items():
        validated_key = validate_string(key, "field_name", max_length=255, pattern=_ID_PATTERN)
        if isinstance(value, str):
            sanitized_item[validated_key] = validate_string(
                value, validated_key, max_length=MAX_FIELD_LENGTH, required=False
            )
        else:
            sanitized_item[validated_key] = value

    table = AWSClients.get_dynamodb_table()
    try:
        response = table.put_item(Item=sanitized_item)
        logger.info(
            "DynamoDB PutItem succeeded",
            extra={"service": SERVICE_NAME, "item_id": sanitized_item["id"]}
        )
        return response
    except ClientError as e:
        logger.error(
            "DynamoDB PutItem failed",
            extra={"service": SERVICE_NAME, "error": str(e)}
        )
        raise


def dynamo_query(partition_key: str, partition_value: str,
                 index_name: Optional[str] = None, limit: int = 100) -> list:
    """Securely query DynamoDB with validated inputs."""
    validated_key = validate_string(partition_key, "partition_key", pattern=_ID_PATTERN)
    validated_value = validate_id(partition_value, "partition_value")

    if limit < 1 or limit > 1000:
        raise InputValidationError("Limit must be between 1 and 1000")

    table = AWSClients.get_dynamodb_table()
    kwargs = {
        "KeyConditionExpression": boto3.dynamodb.conditions.Key(validated_key).eq(validated_value),
        "Limit": limit,
    }
    if index_name:
        kwargs["IndexName"] = validate_string(index_name, "index_name", pattern=_ID_PATTERN)

    try:
        response = table.query(**kwargs)
        return response.get("Items", [])
    except ClientError as e:
        logger.error(
            "DynamoDB Query failed",
            extra={"service": SERVICE_NAME, "error": str(e)}
        )
        raise


def publish_sns_message(message: Dict[str, Any], subject: Optional[str] = None,
                        topic_arn: Optional[str] = None) -> str:
    """Securely publish a message to SNS."""
    target_arn = topic_arn or SNS_TOPIC_ARN
    if not target_arn:
        raise RuntimeError("No SNS topic ARN configured")

    # Validate the topic ARN format to prevent ARN injection
    arn_pattern = re.compile(
        r"^arn:aws:sns:[a-z0-9\-]+:\d{12}:[a-zA-Z0-9\-_]+$"
    )
    if not arn_pattern.match(target_arn):
        raise InputValidationError("Invalid SNS topic ARN format")

    sns = AWSClients.get_sns_client()
    kwargs = {
        "TopicArn": target_arn,
        "Message": json.dumps(message, default=str),
    }
    if subject:
        kwargs["Subject"] = validate_string(subject, "subject", max_length=100)

    try:
        response = sns.publish(**kwargs)
        message_id = response.get("MessageId", "")
        logger.info(
            "SNS message published",
            extra={"service": SERVICE_NAME, "message_id": message_id, "topic": target_arn}
        )
        return message_id
    except ClientError as e:
        logger.error(
            "SNS publish failed",
            extra={"service": SERVICE_NAME, "error": str(e)}
        )
        raise


def send_sqs_message(message: Dict[str, Any], queue_url: Optional[str] = None,
                     delay_seconds: int = 0) -> str:
    """Securely send a message to SQS."""
    target_url = queue_url or SQS_QUEUE_URL
    if not target_url:
        raise RuntimeError("No SQS queue URL configured")

    # Validate queue URL format
    url_pattern = re.compile(
        r"^https://sqs\.[a-z0-9\-]+\.amazonaws\.com/\d{12}/[a-zA-Z0-9\-_]+$"
    )
    if not url_pattern.match(target_url):
        raise InputValidationError("Invalid SQS queue URL format")

    if delay_seconds < 0 or delay_seconds > 900:
        raise InputValidationError("Delay seconds must be between 0 and 900")

    sqs = AWSClients.get_sqs_client()
    try:
        response = sqs.send_message(
            QueueUrl=target_url,
            MessageBody=json.dumps(message, default=str),
            DelaySeconds=delay_seconds,
        )
        message_id = response.get("MessageId", "")
        logger.info(
            "SQS message sent",
            extra={"service": SERVICE_NAME, "message_id": message_id}
        )
        return message_id
    except ClientError as e:
        logger.error(
            "SQS send failed",
            extra={"service": SERVICE_NAME, "error": str(e)}
        )
        raise


def s3_get_object(key: str, bucket: Optional[str] = None) -> bytes:
    """Securely get an object from S3."""
    target_bucket = bucket or S3_BUCKET
    if not target_bucket:
        raise RuntimeError("No S3 bucket configured")

    # Validate key to prevent path traversal
    validated_key = validate_string(key, "s3_key", max_length=1024)
    if ".." in validated_key or validated_key.startswith("/"):
        raise InputValidationError("Invalid S3 key: path traversal detected")

    # Validate bucket name
    bucket_pattern = re.compile(r"^[a-z0-9][a-z0-9.\-]{1,61}[a-z0-9]$")
    if not bucket_pattern.match(target_bucket):
        raise InputValidationError("Invalid S3 bucket name format")

    s3 = AWSClients.get_s3_client()
    try:
        response = s3.get_object(Bucket=target_bucket, Key=validated_key)
        return response["Body"].read()
    except ClientError as e:
        logger.error(
            "S3 GetObject failed",
            extra={"service": SERVICE_NAME, "error": str(e), "key": validated_key}
        )
        raise


def s3_put_object(key: str, body: bytes, content_type: str = "application/json",
                  bucket: Optional[str] = None) -> Dict:
    """Securely put an object into S3 with server-side encryption."""
    target_bucket = bucket or S3_BUCKET
    if not target_bucket:
        raise RuntimeError("No S3 bucket configured")

    validated_key = validate_string(key, "s3_key", max_length=1024)
    if ".." in validated_key or validated_key.startswith("/"):
        raise InputValidationError("Invalid S3 key: path traversal detected")

    bucket_pattern = re.compile(r"^[a-z0-9][a-z0-9.\-]{1,61}[a-z0-9]$")
    if not bucket_pattern.match(target_bucket):
        raise InputValidationError("Invalid S3 bucket name format")

    # Validate content type
    ct_pattern = re.compile(r"^[a-zA-Z0-9][a-zA-Z0-9!#$&\-^_.+]+/[a-zA-Z0-9][a-zA-Z0-9!#$&\-^_.+]+$")
    if not ct_pattern.match(content_type):
        raise InputValidationError("Invalid content type format")

    s3 = AWSClients.get_s3_client()
    try:
        response = s3.put_object(
            Bucket=target_bucket,
            Key=validated_key,
            Body=body,
            ContentType=content_type,
            ServerSideEncryption="aws:kms",
        )
        logger.info(
            "S3 PutObject succeeded",
            extra={"service": SERVICE_NAME, "key": validated_key}
        )
        return response
    except ClientError as e:
        logger.error(
            "S3 PutObject failed",
            extra={"service": SERVICE_NAME, "error": str(e)}
        )
        raise


# ---------------------------------------------------------------------------
# Request routing
# ---------------------------------------------------------------------------
def route_request(event: Dict[str, Any], context: Any) -> Dict:
    """Route incoming requests based on HTTP method and path."""
    # Support both API Gateway v1 and v2 event formats
    http_method = event.get("httpMethod") or event.get("requestContext", {}).get("http", {}).get("method", "")
    path = event.get("path") or event.get("rawPath", "")

    http_method = http_method.upper()

    logger.info(
        "Routing request",
        extra={
            "service": SERVICE_NAME,
            "method": http_method,
            "path": path,
            "request_id": getattr(context, "aws_request_id", "unknown"),
        }
    )

    # Handle CORS preflight
    if http_method == "OPTIONS":
        return build_response(200, {})

    # Route to appropriate handler
    if http_method == "GET" and path.endswith("/health"):
        return handle_health_check(event, context)
    elif http_method == "GET":
        return handle_get(event, context)
    elif http_method == "POST":
        return handle_post(event, context)
    elif http_method == "PUT":
        return handle_put(event, context)
    elif http_method == "DELETE":
        return handle_delete(event, context)
    else:
        return build_response(405, {"error": "Method not allowed"})


# ---------------------------------------------------------------------------
# Request handlers
# ---------------------------------------------------------------------------
def handle_health_check(event: Dict, context: Any) -> Dict:
    """Health check endpoint - no auth required."""
    return build_response(200, {
        "status": "healthy",
        "service": SERVICE_NAME,
        "request_id": getattr(context, "aws_request_id", "unknown"),
    })


def handle_get(event: Dict, context: Any) -> Dict:
    """Handle GET requests - retrieve items."""
    try:
        # Extract and validate path/query parameters
        path_params = event.get("pathParameters") or {}
        query_params = event.get("queryStringParameters") or {}

        item_id = path_params.get("id")
        if item_id:
            validated_id = validate_id(item_id)
            item = dynamo_get_item(validated_id)
            if item:
                return build_response(200, {"data": item})
            return build_response(404, {"error": "Item not found"})

        # List with optional filtering
        limit = 100
        if "limit" in query_params:
            try:
                limit = int(query_params["limit"])
                if limit < 1 or limit > 1000:
                    raise ValueError
            except (ValueError, TypeError):
                return build_response(400, {"error": "Invalid limit parameter"})

        return build_response(200, {"data": [], "count": 0})

    except InputValidationError as e:
        return build_response(400, {"error": str(e)})
    except ClientError as e:
        logger.error("AWS service error", extra={"error": str(e), "service": SERVICE_NAME})
        return build_response(500, {"error": "Internal server error"})


def handle_post(event: Dict, context: Any) -> Dict:
    """Handle POST requests - create items."""
    try:
        body = validate_event_body(event)

        if not body:
            return build_response(400, {"error": "Request body is required"})

        # Validate required fields based on service
        item_id = body.get("id")
        if not item_id:
            return build_response(400, {"error": "Field 'id' is required"})

        validated_id = validate_id(item_id)

        # Check if item already exists
        existing = dynamo_get_item(validated_id)
        if existing:
            return build_response(409, {"error": "Item already exists"})

        # Store item
        item = {"id": validated_id}
        for key, value in body.items():
            if key != "id":
                item[key] = value

        dynamo_put_item(item)

        # Publish event for other microservices
        publish_sns_message({
            "event_type": f"{SERVICE_NAME}.item.created",
            "item_id": validated_id,
            "service": SERVICE_NAME,
        })

        logger.info(
            "Item created",
            extra={"service": SERVICE_NAME, "item_id": validated_id}
        )

        return build_response(201, {"data": item, "message": "Item created"})

    except InputValidationError as e:
        return build_response(400, {"error": str(e)})
    except ClientError as e:
        logger.error("AWS service error", extra={"error": str(e), "service": SERVICE_NAME})
        return build_response(500, {"error": "Internal server error"})


def handle_put(event: Dict, context: Any) -> Dict:
    """Handle PUT requests - update items."""
    try:
        path_params = event.get("pathParameters") or {}
        item_id = path_params.get("id")
        if not item_id:
            return build_response(400, {"error": "Item ID is required in path"})

        validated_id = validate_id(item_id)
        body = validate_event_body(event)

        if not body:
            return build_response(400, {"error": "Request body is required"})

        # Verify item exists
        existing = dynamo_get_item(validated_id)
        if not existing:
            return build_response(404, {"error": "Item not found"})

        # Update item
        updated_item = {"id": validated_id}
        for key, value in body.items():
            if key != "id":
                updated_item[key] = value

        dynamo_put_item(updated_item)

        publish_sns_message({
            "event_type": f"{SERVICE_NAME}.item.updated",
            "item_id": validated_id,
            "service": SERVICE_NAME,
        })

        return build_response(200, {"data": updated_item, "message": "Item updated"})

    except InputValidationError as e:
        return build_response(400, {"error": str(e)})
    except ClientError as e:
        logger.error("AWS service error", extra={"error": str(e), "service": SERVICE_NAME})
        return build_response(500, {"error": "Internal server error"})


def handle_delete(event: Dict, context: Any) -> Dict:
    """Handle DELETE requests - remove items."""
    try:
        path_params = event.get("pathParameters") or {}
        item_id = path_params.get("id")
        if not item_id:
            return build_response(400, {"error": "Item ID is required in path"})

        validated_id = validate_id(item_id)

        existing = dynamo_get_item(validated_id)
        if not existing:
            return build_response(404, {"error": "Item not found"})

        table = AWSClients.get_dynamodb_table()
        table.delete_item(Key={"id": validated_id})

        publish_sns_message({
            "event_type": f"{SERVICE_NAME}.item.deleted",
            "item_id": validated_id,
            "service": SERVICE_NAME,
        })

        logger.info(
            "Item deleted",
            extra={"service": SERVICE_NAME, "item_id": validated_id}
        )

        return build_response(200, {"message": "Item deleted"})

    except InputValidationError as e:
        return build_response(400, {"error": str(e)})
    except ClientError as e:
        logger.error("AWS service error", extra={"error": str(e), "service": SERVICE_NAME})
        return build_response(500, {"error": "Internal server error"})


# ---------------------------------------------------------------------------
# SQS event handler (for queue-triggered invocations)
# ---------------------------------------------------------------------------
def handle_sqs_event(event: Dict[str, Any], context: Any) -> Dict:
    """Process SQS messages with error handling for partial batch failures."""
    batch_item_failures = []

    for record in event.get("Records", []):
        message_id = record.get("messageId", "unknown")
        try:
            body = json.loads(record.get("body", "{}"))

            if len(record.get("body", "")) > MAX_INPUT_LENGTH:
                logger.warning(
                    "SQS message exceeds size limit, skipping",
                    extra={"service": SERVICE_NAME, "message_id": message_id}
                )
                continue

            logger.info(
                "Processing SQS message",
                extra={
                    "service": SERVICE_NAME,
                    "message_id": message_id,
                    "event_type": body.get("event_type", "unknown"),
                }
            )

            # Process the message based on event type
            event_type = body.get("event_type", "")
            if isinstance(event_type, str) and _SAFE_STRING_PATTERN.match(event_type):
                process_event(event_type, body)
            else:
                logger.warning(
                    "Invalid event_type in SQS message",
                    extra={"service": SERVICE_NAME, "message_id": message_id}
                )

        except (json.JSONDecodeError, InputValidationError) as e:
            logger.warning(
                "Invalid SQS message format",
                extra={"service": SERVICE_NAME, "message_id": message_id, "error": str(e)}
            )
        except Exception as e:
            logger.error(
                "Failed to process SQS message",
                extra={"service": SERVICE_NAME, "message_id": message_id, "error": str(e)}
            )
            # Report as failure for partial batch retry
            batch_item_failures.append({"itemIdentifier": message_id})

    return {"batchItemFailures": batch_item_failures}


# ---------------------------------------------------------------------------
# SNS event handler (for topic-triggered invocations)
# ---------------------------------------------------------------------------
def handle_sns_event(event: Dict[str, Any], context: Any) -> None:
    """Process SNS notifications."""
    for record in event.get("Records", []):
        sns_message = record.get("Sns", {})
        message_id = sns_message.get("MessageId", "unknown")
        subject = sns_message.get("Subject", "")
        raw_message = sns_message.get("Message", "{}")

        try:
            if len(raw_message) > MAX_INPUT_LENGTH:
                logger.warning(
                    "SNS message exceeds size limit",
                    extra={"service": SERVICE_NAME, "message_id": message_id}
                )
                continue

            body = json.loads(raw_message)

            logger.info(
                "Processing SNS notification",
                extra={
                    "service": SERVICE_NAME,
                    "message_id": message_id,
                    "subject": subject,
                }
            )

            event_type = body.get("event_type", "")
            if isinstance(event_type, str) and _SAFE_STRING_PATTERN.match(event_type):
                process_event(event_type, body)

        except (json.JSONDecodeError, InputValidationError) as e:
            logger.warning(
                "Invalid SNS message",
                extra={"service": SERVICE_NAME, "message_id": message_id, "error": str(e)}
            )
        except Exception as e:
            logger.error(
                "Failed to process SNS message",
                extra={"service": SERVICE_NAME, "message_id": message_id, "error": str(e)}
            )
            raise  # Re-raise so Lambda retries


def process_event(event_type: str, payload: Dict[str, Any]) -> None:
    """Process a domain event from SNS/SQS. Override per service."""
    logger.info(
        "Processing domain event",
        extra={
            "service": SERVICE_NAME,
            "event_type": event_type,
        }
    )
    # Each microservice implements its own event processing logic here
    # Example:
    # if event_type == "order-processor.item.created":
    #     handle_order_created(payload)


# ---------------------------------------------------------------------------
# Main Lambda handler
# ---------------------------------------------------------------------------
@require_auth
@rate_limit_check
def api_handler(event: Dict[str, Any], context: Any) -> Dict:
    """Authenticated API Gateway handler."""
    return route_request(event, context)


def lambda_handler(event: Dict[str, Any], context: Any) -> Any:
    """
    Universal Lambda entry point that detects the event source and routes
    accordingly. This single handler supports API Gateway, SQS, SNS, and
    direct invocation patterns.
    """
    request_id = getattr(context, "aws_request_id", "unknown")

    try:
        records = event.get("Records", [])

        # Detect SQS trigger
        if records and records[0].get("eventSource") == "aws:sqs":
            logger.info("SQS event detected", extra={
                "service": SERVICE_NAME, "request_id": request_id,
                "record_count": len(records),
            })
            return handle_sqs_event(event, context)

        # Detect SNS trigger
        if records and records[0].get("EventSource") == "aws:sns":
            logger.info("SNS event detected", extra={
                "service": SERVICE_NAME, "request_id": request_id,
                "record_count": len(records),
            })
            return handle_sns_event(event, context)

        # Detect API Gateway (v1 or v2)
        if "httpMethod" in event or "requestContext" in event:
            logger.info("API Gateway event detected", extra={
                "service": SERVICE_NAME, "request_id": request_id,
            })

            # Health check bypasses auth
            path = event.get("path") or event.get("rawPath", "")
            if path.endswith("/health"):
                return handle_health_check(event, context)

            return api_handler(event, context)

        # Direct invocation / scheduled event
        logger.info("Direct invocation detected", extra={
            "service": SERVICE_NAME, "request_id": request_id,
        })
        return {
            "statusCode": 200,
            "service": SERVICE_NAME,
            "request_id": request_id,
            "message": "Direct invocation processed",
        }

    except InputValidationError as e:
        logger.warning("Input validation error", extra={
            "service": SERVICE_NAME, "error": str(e), "request_id": request_id,
        })
        return build_response(400, {"error": str(e)})

    except ClientError as e:
        error_code = e.response.get("Error", {}).get("Code", "Unknown")
        logger.error("AWS client error", extra={
            "service": SERVICE_NAME, "error_code": error_code,
            "request_id": request_id,
        })
        return build_response(500, {"error": "Internal server error"})

    except Exception as e:
        logger.exception("Unhandled exception", extra={
            "service": SERVICE_NAME, "request_id": request_id,
        })
        return build_response(500, {"error": "Internal server error"})